        if (!observed.add_monitor(self_handle(), ref)) {
            //	System.err.println("unable to add monitor to self="+self_handle()+" pid="+observed+" ref="+ref);
            return false;
        }
        this.is_monitoring.put(ref, new ETuple2(observed, object));
