		ERef timer_ref = ref.testReference();
		if (timer_ref == null) throw ERT.badarg();

		long time_left = ETimerTask.read_timer(timer_ref);

		if (time_left > 0) {
			return ERT.box(time_left);
		} else {
			return ERT.FALSE;
		}
